import jsPDF from "jspdf"
import autoTable from "jspdf-autotable"
import { Invoice } from '@/hooks/useInvoices'
import { type InvoiceSettingsPreset } from '@/app/components/finance/invoice-management/InvoiceSettingsManager'

export type { InvoiceSettingsPreset } from '@/app/components/finance/invoice-management/InvoiceSettingsManager'

// Chinese font — Noto Sans SC subset (128KB TTF, 385 characters)
const FONT_B64 = "data:font/truetype;base64,"

const getStatusText = (status: string): string => {
  const m: Record<string,string> = {draft:'草稿',issued:'已开具',sent:'已发送',pending:'待付款',overdue:'已逾期',paid:'已付款',cancelled:'已取消'}
  return m[status] || status
}

function hex2rgb(hex: string) {
  const c = hex.replace('#', '')
  return { r: parseInt(c.substring(0,2),16), g: parseInt(c.substring(2,4),16), b: parseInt(c.substring(4,6),16) }
}

export const generateInvoicePDF = async (invoice: Invoice, settings: InvoiceSettingsPreset): Promise<Blob> => {
  const doc = new jsPDF()
  const pw = doc.internal.pageSize.getWidth()
  const ph = doc.internal.pageSize.getHeight()

  const fd = FONT_B64.replace(/^data:font\/[^;]+;base64,/, '')
  doc.addFileToVFS("NotoSansSC.ttf", fd)
  doc.addFont("NotoSansSC.ttf", "NotoSansSC", "normal")
  const cn = "NotoSansSC"

  const phx = settings.primaryColor || '#1e40af'
  const ahx = settings.accentColor || '#f59e0b'
  const pr = hex2rgb(phx)
  const ar = hex2rgb(ahx)
  const sn = settings.schoolName || '智慧教育学校'

  // Header
  doc.setFillColor(pr.r, pr.g, pr.b)
  doc.rect(0, 0, pw, 40, 'F')
  doc.setFont(cn, "normal")
  doc.setFontSize(18)
  doc.setTextColor(255, 255, 255)
  doc.text(sn, pw/2, 15, { align: "center" })
  if (settings.schoolNameEn) {
    doc.setFont("helvetica", "normal")
    doc.setFontSize(9)
    doc.text(settings.schoolNameEn, pw/2, 22, { align: "center" })
  }
  doc.setFont(cn, "normal")
  doc.setFontSize(11)
  doc.text('INVOICE 发票', pw-14, 14, { align: "right" })
  doc.setDrawColor(200)
  doc.line(14, 45, pw-14, 45)

  // Info
  doc.setFont("helvetica", "normal")
  doc.setFontSize(15)
  doc.setTextColor(pr.r, pr.g, pr.b)
  doc.text(`Invoice #${invoice.invoiceNumber || ''}`, 14, 55)
  doc.setFontSize(9)
  doc.setTextColor(80)
  doc.text(`Issue: ${invoice.issueDate || ''}`, 14, 62)
  doc.text(`Due: ${invoice.dueDate || ''}`, 14, 68)
  doc.setFont(cn, "normal")
  const stu = (invoice as any).studentName || (invoice as any).student || ''
  doc.text(`Student: ${stu}`, 14, 74)
  doc.text(`Status: ${getStatusText(invoice.status || '')}`, 14, 80)

  // School info
  doc.setFont(cn, "normal")
  doc.setFontSize(8)
  doc.setTextColor(120);
  [settings.schoolAddress, settings.schoolPhone, settings.schoolEmail].filter(Boolean).forEach((l,i) => {
    doc.text(l, pw-14, 55+i*5, { align: "right" })
  })

  // Items table
  const rows = (invoice.items || []).map((it: any) => [it.name || it.description || "—", `RM ${(it.amount||0).toFixed(2)}`])
  let fy = 88
  if (rows.length > 0) {
    autoTable(doc, {
      startY: 88,
      head: [["Item", "Amount (RM)"]],
      body: rows,
      theme: "grid",
      headStyles: { fillColor: [pr.r,pr.g,pr.b], textColor: 255, font: cn },
      styles: { font: cn, fontSize: 9 },
      columnStyles: { 1: { halign: "right" } },
    })
    fy = (doc as any).lastAutoTable?.finalY || 88
  }

  // Total
  doc.setFont("helvetica", "bold")
  doc.setFontSize(13)
  doc.setTextColor(pr.r, pr.g, pr.b)
  doc.text(`Total: RM ${(invoice.totalAmount||0).toFixed(2)}`, pw-14, fy+12, { align: "right" })

  // Bank
  if (settings.bankName || settings.bankAccount) {
    const by = fy+25
    doc.setDrawColor(ar.r, ar.g, ar.b)
    doc.setLineWidth(0.5)
    doc.line(14, by, 14, by+20)
    doc.setLineWidth(0.2)
    doc.setFont("helvetica", "bold")
    doc.setFontSize(8)
    doc.setTextColor(80)
    doc.text('Payment Info:', 20, by+4)
    doc.setFont(cn, "normal")
    doc.setFontSize(7)
    let y = by+10
    if (settings.bankName) { doc.text(`Bank: ${settings.bankName}`, 20, y); y+=5 }
    if (settings.bankAccount) { doc.text(`Account: ${settings.bankAccount}`, 20, y); y+=5 }
    if (settings.bankHolder) { doc.text(`Holder: ${settings.bankHolder}`, 20, y) }
  }

  // Notes
  if ((invoice as any).notes) {
    doc.setFont(cn, "normal")
    doc.setFontSize(8)
    doc.setTextColor(100)
    doc.text(`Notes: ${(invoice as any).notes}`, 14, fy+58)
  }

  // Footer
  const fty = ph-15
  doc.setDrawColor(200)
  doc.line(14, fty-5, pw-14, fty-5)
  doc.setFont(cn, "normal")
  doc.setFontSize(7)
  doc.setTextColor(150)
  const ft = settings.footerText || `Thank you for choosing ${sn}.`
  doc.text(ft, pw/2, fty, { align: "center" })
  doc.text(`${sn}${settings.taxNumber ? ' · Tax: '+settings.taxNumber : ''}`, pw/2, fty+5, { align: "center" })

  return doc.output("blob")
}

export const downloadInvoicePDF = async (invoice: Invoice, settings: InvoiceSettingsPreset): Promise<void> => {
  try {
    const blob = await generateInvoicePDF(invoice, settings)
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `Invoice_${invoice.invoiceNumber}.pdf`
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    URL.revokeObjectURL(url)
  } catch (e) {
    console.error('PDF download failed:', e)
    throw new Error('PDF download failed')
  }
}

export const printInvoicePDF = async (invoice: Invoice, settings: InvoiceSettingsPreset): Promise<void> => {
  try {
    const blob = await generateInvoicePDF(invoice, settings)
    const url = URL.createObjectURL(blob)
    const w = window.open(url, '_blank')
    if (w) {
      w.onload = () => { w.print(); setTimeout(() => { w.close(); URL.revokeObjectURL(url) }, 1000) }
    }
  } catch (e) {
    console.error('PDF print failed:', e)
    throw new Error('PDF print failed')
  }
}
